// Create a custom page for user profile uploads
function profile_uploads_page() {
    // Check if user is logged in
    if (!is_user_logged_in()) {
        wp_redirect(wp_login_url());
        exit;
    }

    // Get the current user
    $user = wp_get_current_user();

    // Handle file upload
    if (isset($_FILES['profile_picture']) || isset($_FILES['documents'])) {
        // Handle profile picture upload
        if (isset($_FILES['profile_picture'])) {
            handle_file_upload('profile_picture', 'profile-pictures/');
        }

        // Handle documents upload
        if (isset($_FILES['documents'])) {
            handle_file_upload('documents', 'documents/');
        }

        // Redirect to the profile uploads page with a success message
        wp_redirect(admin_url('profile-uploads.php?success=true'));
        exit;
    }

    // Display the upload form
    // ... form code here ...
}

// Function to handle file upload
function handle_file_upload($file_input, $upload_dir) {
    // Get the uploaded file
    $file = $_FILES[$file_input];

    // Check for errors
    if ($file['error'] > 0) {
        // Handle error
        return;
    }

    // Get the file extension
    $file_extension = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));

    // Allow only specific file types
    $allowed_extensions = array('jpg', 'jpeg', 'png', 'pdf', 'doc', 'docx');
    if (!in_array($file_extension, $allowed_extensions)) {
        // Handle invalid file type
        return;
    }

    // Generate a unique file name
    $file_name = uniqid() . '.' . $file_extension;

    // Move the uploaded file to the specified directory
    move_uploaded_file($file['tmp_name'], WP_CONTENT_DIR . '/uploads/user-files/' . $upload_dir . $file_name);
}
